const items = $input.all();

const output = [];

for (let i = 0; i < items.length; i++) {
  const binaryData = await this.helpers.getBinaryDataBuffer(i, 'data');

  output.push({
    json: {
      ...items[i].json,
      image_base64: binaryData.toString('base64'),
    },
  });
}

return output;

const now = new Date();

const fecha = now.toLocaleDateString('es-PE').replace(/\//g, '-');
const hora = now.toTimeString().slice(0,5).replace(':', '-');

const nombre = `Generación ${fecha} ${hora} - 1`;

return [{
  json: {
    folderName: nombre
  }
}];

return $input.all().map((item, index) => {
  return {
    json: {
      ...item.json,
      fileName: `opcion_${index + 1}.png`
    },
    binary: item.binary
  };
});

const folderId = $json.id;

const items = $items("Nombres a imágenes");

return items.map(item => {
  return {
    json: {
      ...item.json,
      folderId: folderId
    },
    binary: item.binary
  };
});

return $input.all().map((item, index) => {
  const variantes = $('Normalizar Variantes').all();
  const variante = variantes[index]?.json;

  if (!variante) {
    throw new Error(`No existe variante para el índice ${index + 1}`);
  }

  const hashtags = Array.isArray(variante.hashtags)
    ? variante.hashtags.join(' ')
    : '';

  const contenido = `${variante.caption || ''}

${hashtags}
`;

  return {
    json: {
      ...item.json,
      fileName: `opcion_${index + 1}.txt`
    },
    binary: {
      data: {
        data: Buffer.from(contenido, 'utf8').toString('base64'),
        mimeType: 'text/plain',
        fileName: `opcion_${index + 1}.txt`
      }
    }
  };
});

let raw = $json.text
  .replace(/```json|```/g, '')
  .trim();

const variantes = JSON.parse(raw);

return variantes.map((v, index) => ({
  json: {
    ...v,
    variante_numero: index + 1,
    total_variantes: variantes.length,
    image_url: `https://picsum.photos/seed/vet-${index + 1}/512`
  }
}));

const items = $input.all();

const output = [];

for (let i = 0; i < items.length; i++) {
  const binaryData = await this.helpers.getBinaryDataBuffer(i, 'data');

  output.push({
    json: {
      ...items[i].json,
      image_base64: binaryData.toString('base64'),
    },
  });
}

return output;
